// Helper function to get all destinations as array
export const getAllDestinations = () => Object.values(destinations)

// Helper function to get destinations for listing (simplified data)
export const getDestinationsForListing = () => 
  getAllDestinations().map(dest => ({
    id: dest.id,
    name: dest.name,
    slug: dest.slug,
    description: dest.shortDescription,
    image: dest.image,
    highlights: dest.highlightsDetailed.map(h => h.title),
    duration: dest.duration,
    bestTime: dest.bestTime,
    category: dest.category,
    featured: dest.featured
  }))

// Helper function to get destination by slug
export const getDestinationBySlug = (slug: string) => destinations[slug as keyof typeof destinations]

// Helper function to generate static params for Next.js
export const getDestinationSlugs = () => Object.keys(destinations)
